using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpApiServer;

/// <summary>
/// MCP tool classes are plain C# classes. The SDK discovers methods decorated
/// with [McpServerTool] and registers them automatically. Constructor parameters
/// are resolved from DI — here HttpClient comes from IHttpClientFactory via
/// a named/typed registration.
/// </summary>
[McpServerToolType]
public sealed class WeatherTools
{
    private readonly HttpClient _http;

    // The SDK resolves this via DI. Because we register IHttpClientFactory
    // (and a named client) in Program.cs, the framework injects it here.
    public WeatherTools(HttpClient http)
    {
        _http = http;
    }

    [McpServerTool, Description("Get the current weather for a city.")]
    public async Task<string> GetWeather(
        [Description("City name, e.g. 'Seattle'")] string city,
        CancellationToken cancellationToken = default)
    {
        // Example: Open-Meteo geocoding + forecast (free, no key required)
        var geoUrl = $"https://geocoding-api.open-meteo.com/v1/search?name={Uri.EscapeDataString(city)}&count=1";
        var geoJson = await _http.GetFromJsonAsync<JsonElement>(geoUrl, cancellationToken);

        if (!geoJson.TryGetProperty("results", out var results) || results.GetArrayLength() == 0)
            return $"City '{city}' not found.";

        var loc = results[0];
        var lat = loc.GetProperty("latitude").GetDouble();
        var lon = loc.GetProperty("longitude").GetDouble();
        var name = loc.GetProperty("name").GetString();

        var wxUrl = $"https://api.open-meteo.com/v1/forecast?latitude={lat}&longitude={lon}&current_weather=true";
        var wxJson = await _http.GetFromJsonAsync<JsonElement>(wxUrl, cancellationToken);
        var cw = wxJson.GetProperty("current_weather");

        return $"""
            Weather for {name} ({lat:F2}, {lon:F2}):
              Temperature: {cw.GetProperty("temperature").GetDouble()} °C
              Wind speed:  {cw.GetProperty("windspeed").GetDouble()} km/h
              Condition:   WMO code {cw.GetProperty("weathercode").GetInt32()}
            """;
    }

    [McpServerTool, Description("Look up geographic coordinates for a city.")]
    public async Task<string> GeoLookup(
        [Description("City name")] string city,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://geocoding-api.open-meteo.com/v1/search?name={Uri.EscapeDataString(city)}&count=3";
        var json = await _http.GetFromJsonAsync<JsonElement>(url, cancellationToken);

        if (!json.TryGetProperty("results", out var results) || results.GetArrayLength() == 0)
            return $"No results for '{city}'.";

        var lines = new List<string>();
        foreach (var r in results.EnumerateArray())
        {
            var n = r.GetProperty("name").GetString();
            var country = r.TryGetProperty("country", out var c) ? c.GetString() : "??";
            var lat = r.GetProperty("latitude").GetDouble();
            var lon = r.GetProperty("longitude").GetDouble();
            lines.Add($"  {n}, {country} — ({lat:F4}, {lon:F4})");
        }

        return "Results:\n" + string.Join("\n", lines);
    }
}

using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using McpApiServer;

var builder = Host.CreateApplicationBuilder(args);

// Register IHttpClientFactory + a named client with a shared base config.
// The SDK will inject HttpClient into tool constructors from this factory.
builder.Services.AddHttpClient<WeatherTools>(client =>
{
    client.DefaultRequestHeaders.UserAgent.ParseAdd("McpApiServer/1.0");
    client.Timeout = TimeSpan.FromSeconds(30);
});

builder.Services
    .AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();    // Scans for [McpServerToolType] classes

await builder.Build().RunAsync();

