         var cw = wxJson.GetProperty("current_weather");

         return $"""
             Weather for {name} ({lat:F2}, {lon:F2}):
               Temperature: {cw.GetProperty("temperature").GetDouble()} °C
               Wind speed:  {cw.GetProperty("windspeed").GetDouble()} km/h
               Condition:   WMO code {cw.GetProperty("weathercode").GetInt32()}
             """;
     }

     [McpServerTool, Description("Look up geographic coordinates for a city.")]
     public async Task<string> GeoLookup(
         [Description("City name")] string city,
         CancellationToken cancellationToken = default)
     {
         var url = $"https://geocoding-api.open-meteo.com/v1/search?name={Uri.EscapeDataString(city)}&count=3";
         var json = await _http.GetFromJsonAsync<JsonElement>(url, cancellationToken);

         if (!json.TryGetProperty("results", out var results) || results.GetArrayLength() == 0)
             return $"No results for '{city}'.";

         var lines = new List<string>();
         foreach (var r in results.EnumerateArray())
         {
             var n = r.GetProperty("name").GetString();
             var country = r.TryGetProperty("country", out var c) ? c.GetString() : "??";
             var lat = r.GetProperty("latitude").GetDouble();
             var lon = r.GetProperty("longitude").GetDouble();
             lines.Add($"  {n}, {country} — ({lat:F4}, {lon:F4})");
         }

         return "Results:\n" + string.Join("\n", lines);
     }
 }
